files.content:
:host {
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
  width: var(--_card-setting-width);
  min-height: var(--_card-setting-min-height);
  max-width: 100%;
  border: none;
  border-radius: var(--dimension-radius-025);
  background-color: var(--color-background-primary);
  box-shadow: 0 0 0 var(--dimension-stroke-width-012) var(--color-border-tertiary);
  overflow: hidden;
}

:host(.card-setting--editing) {
  background-color: var(--color-background-bold-brand);
  box-shadow: 0 0 0 var(--dimension-stroke-width-025) var(--color-border-bold-brand);
}

.card-setting__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--dimension-space-100);
  height: var(--dimension-size-600);
  flex-shrink: 0;
  padding: var(--dimension-space-100);
  background-color: var(--color-background-secondary);
  border-bottom: var(--dimension-stroke-width-012) solid var(--color-border-tertiary);
  box-sizing: border-box;
}

:host(.card-setting--editing) .card-setting__header {
  background-color: transparent;
  border-bottom-color: transparent;
}

.card-setting__title-wrap {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  align-items: center;
  padding: var(--dimension-space-075);
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

.card-setting__title {
  display: inline-flex;
  align-items: center;
  min-width: 0;
  padding: var(--dimension-space-025);
}

.card-setting__actions {
  display: flex;
  flex-shrink: 0;
  align-items: center;
  gap: var(--dimension-space-100);
}

.card-setting__body {
  flex: 1 1 auto;
  min-height: 0;
  border-radius: 0 0 var(--dimension-radius-025) var(--dimension-radius-025);
  background-color: var(--color-background-primary);
}

:host(.card-setting--editing) .card-setting__body {
  border-radius: var(--dimension-radius-025);
}

import { Component, Event, EventEmitter, h, Host, Prop } from '@stencil/core';

export type CardSettingWidth = 'sm' | 'md' | 'lg';

const CARD_WIDTH_VARS: Record<CardSettingWidth, string> = {
  sm: 'var(--dimension-card-width-sm)',
  md: 'var(--dimension-card-width-md)',
  lg: 'var(--dimension-card-width-lg)',
};

/** Matching height tokens — host min-height so empty cards still reserve space. */
const CARD_HEIGHT_VARS: Record<CardSettingWidth, string> = {
  sm: 'var(--dimension-card-height-sm)',
  md: 'var(--dimension-card-height-md)',
  lg: 'var(--dimension-card-height-lg)',
};

const FAINT_BRAND_TITLE_COLOR = 'var(--color-foreground-faint-brand)';

@Component({
  tag: 'ds-card-setting',
  styleUrl: 'CardSetting.css',
  scoped: true,
})
export class CardSetting {
  /** Section heading shown in the card header. */
  @Prop() heading!: string;

  /**
   * Card width token (`sm` / `md` / `lg`). Also sets host `min-height` to the
   * matching `--dimension-card-height-*` so the body fills available space
   * even when the slot is empty.
   */
  @Prop() cardWidth: CardSettingWidth = 'md';

  /** Controlled edit state — parent owns single-edit orchestration. */
  @Prop() editing = false;

  /** Emits when the user enters or exits edit mode. */
  @Event() dsEditingChange!: EventEmitter<boolean>;

  private enterEdit = () => {
    this.dsEditingChange.emit(true);
  };

  private exitEdit = () => {
    this.dsEditingChange.emit(false);
  };

  render() {
    const editing = this.editing;

    return (
      <Host
        class={{
          'card-setting': true,
          'card-setting--editing': editing,
        }}
        style={{
          '--_card-setting-width': CARD_WIDTH_VARS[this.cardWidth],
          '--_card-setting-min-height': CARD_HEIGHT_VARS[this.cardWidth],
        }}
      >
        <header class="card-setting__header">
          <div class="card-setting__title-wrap">
            <ds-text
              class="card-setting__title"
              variant="text-title-small"
              color={editing ? FAINT_BRAND_TITLE_COLOR : 'primary'}
              as="h2"
            >
              {this.heading}
            </ds-text>
          </div>
          {!editing ? (
            <ds-button-unfilled variant="icon"
              type="button"
              icon="Pencil"
              aria-label="Edit"
              onDsClick={this.enterEdit}
            />
          ) : (
            <div class="card-setting__actions">
              <ds-button-unfilled variant="icon"
                type="button"
                icon="Cross"
                backgroundContrast="bold"
                aria-label="Cancel"
                onDsClick={this.exitEdit}
              />
              <ds-button-filled variant="icon"
                type="button"
                icon="Check"
                intent="brand"
                contrast="faint"
                aria-label="Save"
                onDsClick={this.exitEdit}
              />
            </div>
          )}
        </header>
        <div class="card-setting__body">
          <slot />
        </div>
      </Host>
    );
  }
}
